#!/usr/bin/env python3
"""One-time importer for FaXto release lyrics update."""

from __future__ import annotations

import base64
import gzip
import json
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
PAYLOAD = ''

files = json.loads(gzip.decompress(base64.b64decode(PAYLOAD)).decode("utf-8"))
for relative_path, content in files.items():
    destination = ROOT / relative_path
    destination.parent.mkdir(parents=True, exist_ok=True)
    destination.write_text(content, encoding="utf-8")

for obsolete in (
    ROOT / "scripts" / "import_release_lyrics_update.py",
    ROOT / ".github" / "workflows" / "import-release-lyrics-update.yml",
):
    if obsolete.exists():
        obsolete.unlink()

print(f"Updated {len(files)} release files.")
